const functions = require('@google-cloud/functions-framework');
const { BigQuery } = require('@google-cloud/bigquery');
const { Storage } = require('@google-cloud/storage');

const bigquery = new BigQuery();

const ALLOWED_DATASETS = new Set([
  'analytics',
  'sales',
  'inventory',
  'user_events'
]);

const ALLOWED_AGGREGATIONS = new Set([
  'SUM',
  'AVG',
  'COUNT',
  'MIN',
  'MAX',
  'COUNT_DISTINCT'
]);

const MAX_ROW_LIMIT = 10000000;

function validateInput(input) {
  const errors = [];

  if (!input.dataset || typeof input.dataset !== 'string') {
    errors.push('Invalid or missing dataset name');
  } else if (!ALLOWED_DATASETS.has(input.dataset)) {
    errors.push(`Dataset "${input.dataset}" is not in the allowed list`);
  }

  if (!input.table || typeof input.table !== 'string') {
    errors.push('Invalid or missing table name');
  } else if (!/^[a-zA-Z_][a-zA-Z0-9_]*$/.test(input.table)) {
    errors.push('Table name contains invalid characters');
  }

  if (!input.aggregationColumn || typeof input.aggregationColumn !== 'string') {
    errors.push('Invalid or missing aggregation column');
  } else if (!/^[a-zA-Z_][a-zA-Z0-9_.]*$/.test(input.aggregationColumn)) {
    errors.push('Aggregation column contains invalid characters');
  }

  if (!input.aggregationType || typeof input.aggregationType !== 'string') {
    errors.push('Invalid or missing aggregation type');
  } else if (!ALLOWED_AGGREGATIONS.has(input.aggregationType.toUpperCase())) {
    errors.push(`Aggregation type "${input.aggregationType}" is not supported`);
  }

  if (input.groupByColumns) {
    if (!Array.isArray(input.groupByColumns)) {
      errors.push('groupByColumns must be an array');
    } else {
      for (const col of input.groupByColumns) {
        if (typeof col !== 'string' || !/^[a-zA-Z_][a-zA-Z0-9_.]*$/.test(col)) {
          errors.push(`Invalid group by column: "${col}"`);
        }
      }
    }
  }

  if (input.filterColumn) {
    if (typeof input.filterColumn !== 'string' || !/^[a-zA-Z_][a-zA-Z0-9_.]*$/.test(input.filterColumn)) {
      errors.push('Invalid filter column name');
    }
  }

  if (input.limit) {
    const limit = parseInt(input.limit, 10);
    if (isNaN(limit) || limit <= 0 || limit > MAX_ROW_LIMIT) {
      errors.push(`Limit must be a positive integer up to ${MAX_ROW_LIMIT}`);
    }
  }

  return errors;
}

function buildAggregationQuery(params) {
  const {
    dataset,
    table,
    aggregationColumn,
    aggregationType,
    groupByColumns,
    filterColumn,
    filterValue,
    dateRangeStart,
    dateRangeEnd,
    dateColumn,
    limit
  } = params;

  const aggType = aggregationType.toUpperCase();
  const projectId = process.env.GCP_PROJECT_ID || process.env.GCLOUD_PROJECT;

  let aggExpression;
  if (aggType === 'COUNT_DISTINCT') {
    aggExpression = `COUNT(DISTINCT \`${aggregationColumn}\`)`;
  } else {
    aggExpression = `${aggType}(\`${aggregationColumn}\`)`;
  }

  const tableRef = `\`${projectId}.${dataset}.${table}\``;

  let selectClause;
  let groupByClause = '';

  if (groupByColumns && groupByColumns.length > 0) {
    const groupCols = groupByColumns.map(col => `\`${col}\``).join(', ');
    selectClause = `${groupCols}, ${aggExpression} AS aggregated_value`;
    groupByClause = `GROUP BY ${groupCols}`;
  } else {
    selectClause = `${aggExpression} AS aggregated_value`;
  }

  const conditions = [];
  const queryParams = {};

  if (filterColumn && filterValue !== undefined && filterValue !== null) {
    conditions.push(`\`${filterColumn}\` = @filterValue`);
    queryParams.filterValue = filterValue;
  }

  if (dateColumn && dateRangeStart) {
    if (!/^[a-zA-Z_][a-zA-Z0-9_.]*$/.test(dateColumn)) {
      throw new Error('Invalid date column name');
    }
    conditions.push(`\`${dateColumn}\` >= @dateRangeStart`);
    queryParams.dateRangeStart = dateRangeStart;
  }

  if (dateColumn && dateRangeEnd) {
    conditions.push(`\`${dateColumn}\` <= @dateRangeEnd`);
    queryParams.dateRangeEnd = dateRangeEnd;
  }

  const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';

  let limitClause = '';
  if (limit) {
    limitClause = `LIMIT @resultLimit`;
    queryParams.resultLimit = parseInt(limit, 10);
  }

  const query = `
    SELECT ${selectClause}
    FROM ${tableRef}
    ${whereClause}
    ${groupByClause}
    ${limitClause}
  `.trim();

  return { query, queryParams };
}

async function executeQueryWithRetry(query, queryParams, maxRetries = 3) {
  let lastError;

  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      console.log(`Query attempt ${attempt}/${maxRetries}`);

      const options = {
        query,
        params: queryParams,
        location: process.env.BIGQUERY_LOCATION || 'US',
        maximumBytesBilled: process.env.MAX_BYTES_BILLED || '10000000000',
        useLegacySql: false,
        jobTimeoutMs: 480000,
      };

      const [job] = await bigquery.createQueryJob(options);
      console.log(`Job ${job.id} started.`);

      const [rows] = await job.getQueryResults({
        autoPaginate: true,
        maxResults: MAX_ROW_LIMIT,
      });

      const [metadata] = await job.getMetadata();
      const stats = {
        totalBytesProcessed: metadata.statistics.totalBytesProcessed,
        totalBytesBilled: metadata.statistics.query.totalBytesBilled,
        cacheHit: metadata.statistics.query.cacheHit,
        totalRows: metadata.statistics.query.numDmlAffectedRows || rows.length,
      };

      return { rows, stats, jobId: job.id };
    } catch (error) {
      lastError = error;
      console.error(`Attempt ${attempt} failed: ${error.message}`);

      if (error.code === 403 || error.code === 401) {
        throw new Error('Authentication/Authorization error - not retrying');
      }

      if (error.message && error.message.includes('exceeded')) {
        throw new Error(`Resource limit exceeded: ${error.message}`);
      }

      if (attempt < maxRetries) {
        const backoffMs = Math.min(1000 * Math.pow(2, attempt - 1), 30000);
        console.log(`Retrying in ${backoffMs}ms...`);
        await new Promise(resolve => setTimeout(resolve, backoffMs));
      }
    }
  }

  throw new Error(`Query failed after ${maxRetries} attempts: ${lastError.message}`);
}

async function processInBatches(params, batchSize = 1000000) {
  const results = [];
  let offset = 0;
  let hasMore = true;

  while (hasMore) {
    const batchParams = {
      ...params,
      limit: batchSize,
    };

    const { query, queryParams } = buildAggregationQuery(batchParams);

    const batchQuery = `${query} OFFSET ${offset}`;

    try {
      const { rows, stats } = await executeQueryWithRetry(batchQuery, queryParams);

      if (rows.length === 0) {
        hasMore = false;
      } else {
        results.push(...rows);
        offset += batchSize;
        console.log(`Processed batch: ${results.length} total rows so far`);

        if (rows.length < batchSize) {
          hasMore = false;
        }
      }
    } catch (error) {
      console.error(`Batch processing error at offset ${offset}: ${error.message}`);
      throw error;
    }
  }

  return results;
}

async function saveResultsToStorage(results, bucketName, fileName) {
  if (!bucketName || !fileName) return null;

  if (!/^[a-zA-Z0-9._-]+$/.test(bucketName)) {
    throw new Error('Invalid bucket name');
  }
  if (!/^[a-zA-Z0-9._/-]+$/.test(fileName)) {
    throw new Error('Invalid file name');
  }

  const storage = new Storage();
  const bucket = storage.bucket(bucketName);
  const file = bucket.file(fileName);

  const jsonData = JSON.stringify(results, null, 2);

  await file.save(jsonData, {
    contentType: 'application/json',
    metadata: {
      cacheControl: 'no-cache',
    },
  });

  console.log(`Results saved to gs://${bucketName}/${fileName}`);
  return `gs://${bucketName}/${fileName}`;
}

functions.http('processLargeDataset', async (req, res) => {
  const startTime = Date.now();

  res.set('Content-Type', 'application/json');
  res.set('X-Content-Type-Options', 'nosniff');
  res.set('X-Frame-Options', 'DENY');
  res.set('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');

  if (req.method !== 'POST') {
    res.status(405).json({
      error: 'Method not allowed',
      message: 'Only POST requests are accepted',
    });
    return;
  }

  const authHeader = req.headers['authorization'];
  if (process.env.REQUIRE_AUTH === 'true') {
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      res.status(401).json({
        error: 'Unauthorized',
        message: 'Missing or invalid authorization header',
      });
      return;
    }
  }

  try {
    const params = req.body;

    if (!params || typeof params !== 'object') {
      res.status(400).json({
        error: 'Bad Request',
        message: 'Request body must be a valid JSON object',
      });
      return;
    }

    const validationErrors = validateInput(params);
    if (validationErrors.length > 0) {
      res.status(400).json({
        error: 'Validation Error',
        messages: validationErrors,
      });
      return;
    }

    console.log(`Processing aggregation request: ${params.aggregationType} on ${params.dataset}.${params.table}`);

    const { query, queryParams } = buildAggregationQuery(params);
    console.log('Executing query...');

    const { rows, stats, jobId } = await executeQueryWithRetry(query, queryParams);

    console.log(`Query completed. Rows returned: ${rows.length}`);
    console.log(`Bytes processed: ${stats.totalBytesProcessed}`);

    let storageUri = null;
    if (params.outputBucket && params.outputFile) {
      storageUri = await saveResultsToStorage(
        rows,
        params.outputBucket,
        params.outputFile
      );
    }

    const processingTimeMs = Date.now() - startTime;

    const response = {
      success: true,
      metadata: {
        jobId,
        processingTimeMs,
        totalRows: rows.length,
        bytesProcessed: stats.totalBytesProcessed,
        bytesBilled: stats.totalBytesBilled,
        cacheHit: stats.cacheHit,
        aggregationType: params.aggregationType,
        dataset: params.dataset,
        table: params.table,
      },
      storageUri,
    };

    if (rows.length <= 10000) {
      response.data = rows;
    } else {
      response.data = rows.slice(0, 1000);
      response.metadata.truncated = true;
      response.metadata.message = `Results truncated to 1000 rows. Full results (${rows.length} rows) saved to ${storageUri || 'storage (provide outputBucket and outputFile)'}`;

      if (!storageUri) {
        const tempBucket = process.env.TEMP_RESULTS_BUCKET;
        if (tempBucket) {
          const tempFile = `results/aggregation_${jobId}_${Date.now()}.json`;
          storageUri = await saveResultsToStorage(rows, tempBucket, tempFile);
          response.storageUri = storageUri;
        }
      }
    }

    console.log(`Request completed in ${processingTimeMs}ms`);
    res.status(200).json(response);

  } catch (error) {
    const processingTimeMs = Date.now() - startTime;
    console.error(`Error processing request: ${error.message}`);
    console.error(error.stack);

    const statusCode = error.message.includes('Authentication') ? 403 :
                       error.message.includes('not found') ? 404 :
                       error.message.includes('exceeded') ? 429 : 500;

    res.status(statusCode).json({
      success: false,
      error: 'Processing Error',
      message: process.env.NODE_ENV === 'production'
        ? 'An error occurred during data processing'
        : error.message,
      processingTimeMs,
    });
  }
});

